                { id: 'read_2_2', question: 'How long does reading need to reduce stress according to the University of Sussex?', options: ['Six minutes', 'Thirty minutes', 'One hour', 'Two hours'], correct: 0, explanation: '"reading for just six minutes can reduce stress levels by up to 68%".', tip: 'Tìm "University of Sussex" → "six minutes".' },
                { id: 'read_2_3', question: 'What do many young people prefer doing instead of reading?', options: ['Watching videos or playing games on phones', 'Listening to music', 'Going for walks', 'Talking to friends'], correct: 0, explanation: '"prefer watching videos or playing games on their phones".', tip: 'Tìm "prefer...rather than".' },
                { id: 'read_2_4', question: 'How long should students read every day according to experts?', options: ['At least 30 minutes', 'At least 1 hour', 'At least 6 minutes', 'At least 2 hours'], correct: 0, explanation: '"read for at least 30 minutes every day".', tip: 'Tìm "experts recommend".' }
